mapper.select:
SELECT m.id, m.status, m.reimbursement_title AS reimbursementTitle, m.business_trip_reason AS businessTripReason, m.subsidy_total AS subsidyTotal, m.creation_time AS creationTime, e.reimburser_id AS reimburserId, e.reimburser_name AS reimburserName, e.reimburser_no AS reimburserNo, d.reim_department_id AS reimDepartmentId, d.reim_department_name AS reimDepartmentName, d.reim_department_no AS reimDepartmentNo, c.reim_company_id AS reimCompanyId, c.reim_company_name AS reimCompanyName, b.business_type_id AS businessTypeId, b.business_type_name AS businessTypeName FROM fk_reim_main m LEFT JOIN fk_reim_employee e ON m.reimburser_id = e.reimburser_id LEFT JOIN fk_reim_department d ON m.reim_department_id = d.reim_department_id LEFT JOIN fk_reim_company c ON m.reim_company_id = c.reim_company_id LEFT JOIN fk_business_type b ON m.business_type_id = b.business_type_id
AND m.id LIKE CONCAT('%', #{query.reimbursementNo}, '%')
AND m.reimbursement_title LIKE CONCAT('%', #{query.reimbursementTitle}, '%')
AND m.business_trip_reason LIKE CONCAT('%', #{query.businessTripReason}, '%')
AND m.reim_company_id = #{query.reimCompanyId}
AND m.reim_department_id = #{query.reimDepartmentId}
AND m.reimburser_id = #{query.reimburserId}
AND m.business_type_id = #{query.businessTypeId}
AND m.status = #{query.status}
ORDER BY m.creation_time DESC
